// ═══════════════════════════════════════════════════════════════
// TEMPLATE SANITIZADO — db_crear_prereserva v2
// ═══════════════════════════════════════════════════════════════
// Este JSON es un template genérico para importar en n8n.
// No contiene credenciales, IDs de Sheet ni IDs de workflow reales.
//
// Antes de importar, reemplazar los siguientes placeholders:
//   __SHEETS_ID__                         → ID del Google Sheet del entorno
//   __CREDENTIAL_ID__                     → ID de la credencial OAuth en n8n
//   __CREDENTIAL_NAME__                   → Nombre de la credencial OAuth en n8n
//   __RECALCULAR_DISPONIBILIDAD_WORKFLOW_ID__ → ID del workflow db_recalcular_disponibilidad
//
// El mismo template sirve para DEV, TEST y PROD.
// Solo cambia SHEETS_ID y las credenciales.
//
// DEPENDENCIA CRÍTICA:
// db_crear_prereserva llama a db_recalcular_disponibilidad como subworkflow.
// db_recalcular_disponibilidad DEBE tener un trigger
// 'When Executed by Another Workflow' conectado al nodo inicial.
// db_recalcular_disponibilidad v8 ejecuta recálculo COMPLETO:
// limpia DISPONIBILIDAD_CACHE!A2:R y reescribe las 300 filas.
// Por eso NO se envían id_cabanas ni fechas al subworkflow.
// Cuando exista una versión de recálculo parcial real (que no borre
// la cache completa antes de escribir), actualizar Prep Recalcular.
// ═══════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// NODO 1 — Resolver Input
// ═══════════════════════════════════════════════════════════════
// ALCANCE v2:
// ✅ Valida input completo
// ✅ Verifica disponibilidad en dos capas (cache + fuentes directas)
// ✅ Valida cabaña: existe, activa, no bloqueada, capacidad OK
// ✅ Horario checkin domingo: usa hora_checkin_domingo o fallback 18:00
// ✅ Crea PRE_RESERVA con estado pendiente_pago
// ✅ Calcula expira_en desde CONFIGURACION_GENERAL
// ✅ Escribe LOG_CAMBIOS en ambas ramas (éxito y conflicto)
// ✅ Llama db_recalcular_disponibilidad síncrono (recálculo completo)
// ✅ continueOnFail en nodo Execute Workflow para manejar fallo post-escritura
//
// ❌ FUERA DE ALCANCE en v2 (diferido explícitamente):
//    - Validación de id_consulta contra hoja CONSULTAS
//      (se acepta como dato del input; agregar en v3 cuando sea necesario)
//    - Motor de precios — monto_total y monto_sena son input opcional
//      (precio_pendiente = true en output si no vienen)
//    - MercadoPago, WhatsApp, pagos, confirmación de reserva
//    - OVERRIDES_OPERATIVOS, escalonamiento de check-in, bot
//    - Recálculo parcial por cabaña/fechas — se usa recálculo completo
//      hasta que exista una versión de db_recalcular_disponibilidad
//      que soporte scope parcial sin borrar el resto de la cache
//
// ⚠️  SHEETS_ID — __ENTORNO__
// Si el Sheet cambia, actualizar aquí y en todos los nodos Google Sheets.
// Valor actual: __SHEETS_ID__
//
// ⚠️  WORKFLOW ID — Ejecutar db_recalcular_disponibilidad
// Antes de ejecutar este workflow, reemplazar en el nodo
// 'Ejecutar db_recalcular_disponibilidad' el valor:
//   __RECALCULAR_DISPONIBILIDAD_WORKFLOW_ID__
// por el ID real del workflow __RECALCULAR_DISPONIBILIDAD_WORKFLOW_NAME__.
// El ID está en la URL del workflow: /workflow/<ID>
//
// ⚠️  CONCURRENCIA = 1
// Configurar en n8n → Settings del workflow → Max Concurrency = 1.
// Nunca ejecutar en paralelo.
//
// ⚠️  id_prereserva — estrategia: max + 1
// Race condition posible si dos ejecuciones leen el max simultáneamente.
// Con concurrencia = 1 el riesgo es mínimo.
// Solución definitiva para alta concurrencia: UUID o DB transaccional.
//
// ⚠️  RIESGO TÉCNICO — fallo post-escritura sin rollback
// Si db_recalcular_disponibilidad falla DESPUÉS de que PRE_RESERVAS
// fue escrita, la pre-reserva existe pero la cache no refleja el bloqueo.
// No hay rollback automático en Google Sheets.
// El workflow devuelve recalculo_cache='warning' en ese caso.
// Acción correctiva: ejecutar db_recalcular_disponibilidad manualmente.
// ═══════════════════════════════════════════════════════════════

const SHEETS_ID = '__SHEETS_ID__'; // __ENTORNO__

const CANALES_ORIGEN_VALIDOS = ['whatsapp', 'instagram', 'web', 'manual'];
const CANALES_PAGO_VALIDOS   = ['mp_link', 'transferencia_bancaria', 'transferencia_mp', 'cripto', 'efectivo'];
const CANAL_PAGO_DEFAULT     = 'transferencia_bancaria';

// ── MANUAL_INPUT ─────────────────────────────────────────────────
// Editar estos valores para pruebas manuales del entorno correspondiente.
// Se usan SOLO si el Manual Trigger viene vacío (sin payload).
// En producción el input vendrá del Webhook o del bot.
const MANUAL_INPUT = {
  id_consulta:         1,
  id_cabana:           1,
  id_huesped:          null,
  fecha_in:            '2026-07-05',
  fecha_out:           '2026-07-06',
  hora_checkin:        '',          // vacío = calcular según día y config
  hora_checkout:       '',          // vacío = usar hora_checkout_default
  personas:            5,
  monto_total:         null,        // null = precio_pendiente
  monto_sena:          null,        // null = precio_pendiente
  canal_pago_esperado: '',          // vacío = usar default transferencia_bancaria
  canal_origen:        'manual',
  notas:               '',
  source_event:        'manual_test'   // editar según entorno
};
// ─────────────────────────────────────────────────────────────

const raw            = $input.first()?.json ?? {};
const usandoManualInput = !raw.id_cabana && !raw.fecha_in;
const input          = usandoManualInput ? MANUAL_INPUT : raw;

const id_consulta         = input.id_consulta         ?? null;
const id_cabana           = parseInt(String(input.id_cabana ?? ''), 10);
const id_huesped          = input.id_huesped          ?? null;
const fecha_in            = String(input.fecha_in     ?? '').trim();
const fecha_out           = String(input.fecha_out    ?? '').trim();
const hora_checkin_input  = String(input.hora_checkin  ?? '').trim();
const hora_checkout_input = String(input.hora_checkout ?? '').trim();
const personas            = parseInt(String(input.personas ?? ''), 10);
const monto_total         = (input.monto_total !== null && input.monto_total !== undefined && input.monto_total !== '')
                              ? parseFloat(String(input.monto_total)) : null;
const monto_sena          = (input.monto_sena !== null && input.monto_sena !== undefined && input.monto_sena !== '')
                              ? parseFloat(String(input.monto_sena)) : null;
const canal_origen        = String(input.canal_origen        ?? '').trim();
const canal_pago_esperado = String(input.canal_pago_esperado ?? '').trim() || CANAL_PAGO_DEFAULT;
const notas               = String(input.notas        ?? '').trim();
const source_event        = String(input.source_event ?? 'manual').trim();

// ── Validaciones ─────────────────────────────────────────────
const errores = [];

if (isNaN(id_cabana) || id_cabana <= 0)
  errores.push('id_cabana es obligatorio y debe ser entero positivo');
if (isNaN(personas) || personas <= 0)
  errores.push('personas es obligatorio y debe ser entero positivo');
if (!fecha_in)
  errores.push('fecha_in es obligatorio (YYYY-MM-DD)');
if (!fecha_out)
  errores.push('fecha_out es obligatorio (YYYY-MM-DD)');
if (!CANALES_ORIGEN_VALIDOS.includes(canal_origen))
  errores.push(`canal_origen inválido: '${canal_origen}'. Válidos: ${CANALES_ORIGEN_VALIDOS.join(', ')}`);
if (!CANALES_PAGO_VALIDOS.includes(canal_pago_esperado))
  errores.push(`canal_pago_esperado inválido: '${canal_pago_esperado}'. Válidos: ${CANALES_PAGO_VALIDOS.join(', ')}`);

if (fecha_in && fecha_out) {
  const fi = new Date(fecha_in  + 'T12:00:00Z');
  const fo = new Date(fecha_out + 'T12:00:00Z');
  if (isNaN(fi.getTime())) errores.push('fecha_in inválida');
  if (isNaN(fo.getTime())) errores.push('fecha_out inválida');
  if (!isNaN(fi.getTime()) && !isNaN(fo.getTime()) && fo <= fi)
    errores.push('fecha_out debe ser posterior a fecha_in (intervalo semiabierto [fecha_in, fecha_out))');
}

// Generar lista de fechas [fecha_in, fecha_out)
function generarFechasRango(fIn, fOut) {
  const fechas = [];
  const d = new Date(fIn + 'T12:00:00Z');
  const o = new Date(fOut + 'T12:00:00Z');
  while (d < o) {
    fechas.push(d.toISOString().split('T')[0]);
    d.setUTCDate(d.getUTCDate() + 1);
  }
  return fechas;
}

const fechas_rango = (fecha_in && fecha_out && errores.length === 0)
  ? generarFechasRango(fecha_in, fecha_out)
  : [];

if (errores.length > 0) {
  return [{ json: { ok: false, error: 'input_invalido', detalle: errores, _validado: false } }];
}

return [{ json: {
  SHEETS_ID,
  id_consulta,
  id_cabana,
  id_huesped,
  fecha_in,
  fecha_out,
  hora_checkin_input,
  hora_checkout_input,
  personas,
  monto_total,
  monto_sena,
  precio_pendiente: (monto_total === null || monto_sena === null),
  canal_origen,
  canal_pago_esperado,
  notas,
  source_event,
  fechas_rango,
  ts_inicio: new Date().toISOString(),
  _validado: true,
  _usando_manual_input: usandoManualInput
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 2 — Verificar Cabaña + Calcular horarios base
// ═══════════════════════════════════════════════════════════════
// Valida:
//   1. id_cabana existe en CABAÑAS
//   2. activa = TRUE
//   3. bloqueada = FALSE (bloqueo operativo de la cabaña,
//      distinto de los BLOQUEOS por fecha)
//   4. personas <= capacidad_max
//
// Calcula hora_checkin_base:
//   - Si hora_checkin_input no está vacío → usar ese valor
//   - Si fecha_in es domingo (UTC day = 0) → usar hora_checkin_domingo
//     de CONFIGURACION_GENERAL, o fallback '18:00'
//   - En cualquier otro día → usar hora_checkin_default
//     de CONFIGURACION_GENERAL, o fallback '13:00'
//
// Calcula hora_checkout_base:
//   - Si hora_checkout_input no está vacío → usar ese valor
//   - Si no → usar hora_checkout_default de CONFIGURACION_GENERAL,
//     o fallback '10:00'
// ═══════════════════════════════════════════════════════════════

const inputData = $('Resolver Input').first().json;

function normBool(v) {
  if (v === true || v === 1) return true;
  if (typeof v === 'string') return v.trim().toUpperCase() === 'TRUE' || v.trim() === '1';
  return false;
}

function esDomingo(fechaStr) {
  if (!fechaStr) return false;
  const d = new Date(fechaStr + 'T12:00:00Z');
  return !isNaN(d.getTime()) && d.getUTCDay() === 0;
}

// Cabañas
const cabanas = ($('Agg CABAÑAS').first()?.json?.data ?? [])
  .filter(c => c && Object.keys(c).some(k => String(c[k]).trim() !== ''));

const cabana = cabanas.find(c => parseInt(String(c.id_cabana), 10) === inputData.id_cabana);

if (!cabana) {
  return [{ json: {
    ok: false, error: 'input_invalido',
    detalle: [`id_cabana ${inputData.id_cabana} no existe en CABAÑAS`],
    _verificacion_cabana: false
  }}];
}

if (!normBool(cabana.activa)) {
  return [{ json: {
    ok: false, error: 'cabana_no_disponible',
    detalle: [`Cabaña ${inputData.id_cabana} no está activa`],
    _verificacion_cabana: false
  }}];
}

if (normBool(cabana.bloqueada)) {
  return [{ json: {
    ok: false, error: 'cabana_no_disponible',
    detalle: [`Cabaña ${inputData.id_cabana} está bloqueada operativamente (campo CABAÑAS.bloqueada)`],
    _verificacion_cabana: false
  }}];
}

const capacidad_max = parseInt(String(cabana.capacidad_max ?? '0'), 10);
if (inputData.personas > capacidad_max) {
  return [{ json: {
    ok: false, error: 'capacidad_excedida',
    detalle: [`personas=${inputData.personas} excede capacidad_max=${capacidad_max} de la cabaña ${inputData.id_cabana}`],
    _verificacion_cabana: false
  }}];
}

// Config → objeto plano
const configRows = ($('Agg CONFIG').first()?.json?.data ?? [])
  .filter(r => r && Object.keys(r).some(k => String(r[k]).trim() !== ''));
const config = {};
for (const row of configRows) {
  if (row.clave && String(row.clave).trim())
    config[String(row.clave).trim()] = String(row.valor ?? '').trim();
}

// Calcular hora_checkin_base con lógica de domingo
let hora_checkin_base;
if (inputData.hora_checkin_input) {
  hora_checkin_base = inputData.hora_checkin_input;
} else if (esDomingo(inputData.fecha_in)) {
  hora_checkin_base = config.hora_checkin_domingo ?? '18:00';
} else {
  hora_checkin_base = config.hora_checkin_default ?? '13:00';
}

// Calcular hora_checkout_base
const hora_checkout_base = inputData.hora_checkout_input
  ? inputData.hora_checkout_input
  : (config.hora_checkout_default ?? '10:00');

const prereserva_expiracion_minutos = (() => {
  const v = parseInt(config.prereserva_expiracion_minutos ?? '60', 10);
  return isNaN(v) ? 60 : v;
})();

return [{ json: {
  inputData,
  cabana,
  config,
  hora_checkin_base,
  hora_checkout_base,
  prereserva_expiracion_minutos,
  _verificacion_cabana: true
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 3 — Verificación Capa 1: DISPONIBILIDAD_CACHE
// ═══════════════════════════════════════════════════════════════
// Verifica el rango [fecha_in, fecha_out) contra DISPONIBILIDAD_CACHE.
//
// Estados que BLOQUEAN:
//   - 'ocupada'
//   - 'bloqueada'
//   - 'limite_escalonamiento'
//
// Estados que NO bloquean (noche libre):
//   - 'disponible'
//   - 'checkout_disponible' (hay checkout ese día pero la noche queda libre)
//
// Si alguna fecha del rango no aparece en cache, se trata como
// dato faltante y se pasa a Capa 2 para verificación directa.
// Esto cubre el caso de cache desactualizada o rango fuera del ciclo.
// ═══════════════════════════════════════════════════════════════

const ctx       = $input.first().json;
const inputData = ctx.inputData;

const cacheRows = ($('Agg CACHE').first()?.json?.data ?? [])
  .filter(r => r && Object.keys(r).some(k => String(r[k]).trim() !== ''));

const ESTADOS_BLOQUEANTES = ['ocupada', 'bloqueada', 'limite_escalonamiento'];

const cacheMap = {};
for (const row of cacheRows) {
  if (row.id_cabana && row.fecha)
    cacheMap[`${row.id_cabana}__${row.fecha}`] = String(row.estado ?? '').trim();
}

const conflictos         = [];
const fechas_sin_cache   = [];

for (const fecha of inputData.fechas_rango) {
  const estado = cacheMap[`${inputData.id_cabana}__${fecha}`];
  if (!estado) {
    fechas_sin_cache.push(fecha);
    continue;
  }
  if (ESTADOS_BLOQUEANTES.includes(estado))
    conflictos.push({ fecha, estado, fuente: 'DISPONIBILIDAD_CACHE' });
}

if (conflictos.length > 0) {
  return [{ json: {
    ok: false,
    error: 'no_disponible',
    motivo: 'Fechas bloqueadas según DISPONIBILIDAD_CACHE',
    conflictos,
    _capa1_ok: false
  }}];
}

return [{ json: { ctx, fechas_sin_cache, _capa1_ok: true } }];

// ═══════════════════════════════════════════════════════════════
// NODO 4 — Verificación Capa 2: Fuentes directas
// ═══════════════════════════════════════════════════════════════
// Segunda verificación justo antes de escribir.
// Verifica directamente RESERVAS, PRE_RESERVAS y BLOQUEOS.
//
// Si Capa 1 pasó pero Capa 2 detecta conflicto:
//   → no escribir PRE_RESERVA
//   → retornar {_capa2_ok: false} para que el IF dispare
//     el nodo de LOG warning + error controlado
//
// ⚠️  RIESGO TÉCNICO residual:
// Con concurrencia = 1 el riesgo de race condition es mínimo.
// Solución definitiva: DB transaccional con SELECT FOR UPDATE.
// Documentado como deuda técnica.
//
// Lógica de solapamiento de rangos (intervalo semiabierto):
//   Dos rangos [A, B) y [C, D) se solapan si: A < D && B > C
// ═══════════════════════════════════════════════════════════════

const prevCtx   = $input.first().json;
const ctx       = prevCtx.ctx;
const inputData = ctx.inputData;
const ahora     = new Date();

function toYMD(val) {
  if (!val && val !== 0) return null;
  if (val instanceof Date) return isNaN(val.getTime()) ? null : val.toISOString().split('T')[0];
  if (typeof val === 'number') {
    const d = new Date(Date.UTC(1899, 11, 30) + val * 86400000);
    return isNaN(d.getTime()) ? null : d.toISOString().split('T')[0];
  }
  const s = String(val).trim();
  if (!s) return null;
  const p = s.split('T')[0];
  if (/^\d{4}-\d{2}-\d{2}$/.test(p)) return p;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d.toISOString().split('T')[0];
}

function parseTimestamp(val) {
  if (!val && val !== 0) return null;
  if (val instanceof Date) return isNaN(val.getTime()) ? null : val;
  if (typeof val === 'number') {
    const d = val < 200000
      ? new Date(Date.UTC(1899, 11, 30) + val * 86400000)
      : new Date(val);
    return isNaN(d.getTime()) ? null : d;
  }
  const s = String(val).trim();
  if (!s) return null;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
}

function parseFechaMs(val) {
  const ymd = toYMD(val);
  if (!ymd) return null;
  const [y, m, d] = ymd.split('-').map(Number);
  return Date.UTC(y, m - 1, d, 12, 0, 0);
}

function normBool(v) {
  if (v === true || v === 1) return true;
  if (typeof v === 'string') return v.trim().toUpperCase() === 'TRUE' || v.trim() === '1';
  return false;
}

const reservas    = ($('Agg RESERVAS').first()?.json?.data    ?? []).filter(r => r && Object.keys(r).some(k => String(r[k]).trim() !== ''));
const prereservas = ($('Agg PRE_RESERVAS').first()?.json?.data ?? []).filter(p => p && Object.keys(p).some(k => String(p[k]).trim() !== ''));
const bloqueos    = ($('Agg BLOQUEOS').first()?.json?.data    ?? []).filter(b => b && Object.keys(b).some(k => String(b[k]).trim() !== ''));

const id_cabana = inputData.id_cabana;
const msIn      = parseFechaMs(inputData.fecha_in);
const msOut     = parseFechaMs(inputData.fecha_out);
const conflictos = [];

// ── RESERVAS: estado IN ('confirmada', 'activa') ──────────────
for (const r of reservas) {
  if (parseInt(String(r.id_cabana), 10) !== id_cabana) continue;
  if (!['confirmada', 'activa'].includes(String(r.estado ?? ''))) continue;
  const rIn  = parseFechaMs(r.fecha_checkin);
  const rOut = parseFechaMs(r.fecha_checkout);
  if (rIn === null || rOut === null) continue;
  if (rIn < msOut && rOut > msIn)
    conflictos.push({ fuente: 'RESERVAS', id_reserva: r.id_reserva, fecha_checkin: r.fecha_checkin, fecha_checkout: r.fecha_checkout, estado: r.estado });
}

// ── PRE_RESERVAS: pendiente_pago y no vencida ─────────────────
for (const p of prereservas) {
  if (parseInt(String(p.id_cabana), 10) !== id_cabana) continue;
  if (String(p.estado ?? '') !== 'pendiente_pago') continue;
  const expiraTs = parseTimestamp(p.expira_en);
  if (!expiraTs || expiraTs <= ahora) continue;
  const pIn  = parseFechaMs(p.fecha_in);
  const pOut = parseFechaMs(p.fecha_out);
  if (pIn === null || pOut === null) continue;
  if (pIn < msOut && pOut > msIn)
    conflictos.push({ fuente: 'PRE_RESERVAS', id_prereserva: p.id_prereserva, fecha_in: p.fecha_in, fecha_out: p.fecha_out, expira_en: p.expira_en });
}

// ── BLOQUEOS: activo = TRUE, rango [fecha_desde, fecha_hasta) ─
for (const b of bloqueos) {
  const aplicaCabana = !b.id_cabana || String(b.id_cabana).trim() === '' || parseInt(String(b.id_cabana), 10) === id_cabana;
  if (!aplicaCabana) continue;
  if (!normBool(b.activo)) continue;
  const bIn  = parseFechaMs(b.fecha_desde);
  const bOut = parseFechaMs(b.fecha_hasta);
  if (bIn === null || bOut === null) continue;
  if (bIn < msOut && bOut > msIn)
    conflictos.push({ fuente: 'BLOQUEOS', id_bloqueo: b.id_bloqueo, fecha_desde: b.fecha_desde, fecha_hasta: b.fecha_hasta });
}

if (conflictos.length > 0) {
  return [{ json: {
    _capa2_ok:   false,
    conflictos,
    inputData,
    source_event: inputData.source_event
  }}];
}

return [{ json: {
  _capa2_ok:    true,
  inputData,
  prereservas,
  ctx
}}];

// Capa 2 detectó conflicto que Capa 1 no vio.
// Indica race condition o cache desactualizada.
// Prepara LOG warning + output de error controlado.
const d     = $input.first().json;
const ahora = new Date();

return [{ json: {
  _log: {
    id_log:           `LOG-PRERESERVA-CONFLICTO-${ahora.getTime()}`,
    fecha_hora:        ahora.toISOString(),
    tabla_afectada:   'PRE_RESERVAS',
    id_registro:      'N/A',
    campo_modificado: 'verificacion_capa2',
    valor_anterior:   '',
    valor_nuevo:      '',
    modificado_por:   'n8n',
    source_event:     d.inputData?.source_event ?? 'db_crear_prereserva',
    nivel:            'warning',
    detalle: JSON.stringify({
      motivo:    'no_disponible_conflicto_detectado',
      id_cabana: d.inputData?.id_cabana,
      fecha_in:  d.inputData?.fecha_in,
      fecha_out: d.inputData?.fecha_out,
      conflictos: d.conflictos
    })
  },
  _output: {
    ok:         false,
    error:      'no_disponible_conflicto_detectado',
    conflictos: d.conflictos
  }
}}];

// ═══════════════════════════════════════════════════════════════
// NODO 5 — Preparar Fila PRE_RESERVAS
// ═══════════════════════════════════════════════════════════════
// Calcula id_prereserva (max + 1), expira_en, y construye la fila.
//
// ⚠️  PRECIO — fuera de alcance en v2:
// monto_total y monto_sena son input opcional.
// Si no vienen → quedan vacíos y precio_pendiente = true.
// La obligatoriedad del precio antes de confirmar la reserva
// quedará en db_confirmar_reserva o cuando se implemente
// db_calcular_precio (motor de precios, Etapa 3).
// ═══════════════════════════════════════════════════════════════

const d          = $input.first().json;
const inputData  = d.inputData;
const prereservas = d.prereservas;
const ctx        = d.ctx;
const ahora      = new Date();

// id_prereserva = max + 1
// ⚠️  Race condition posible. Ver comentario en Resolver Input.
const ids = prereservas
  .map(p => parseInt(String(p.id_prereserva ?? ''), 10))
  .filter(n => !isNaN(n) && n > 0);
const id_prereserva = (ids.length > 0 ? Math.max(...ids) : 0) + 1;

// expira_en = ahora + prereserva_expiracion_minutos
const minutos   = ctx.prereserva_expiracion_minutos ?? 60;
const expira_en = new Date(ahora.getTime() + minutos * 60 * 1000).toISOString();

const fila = {
  id_prereserva,
  id_consulta:         inputData.id_consulta   ?? '',
  id_cabana:           inputData.id_cabana,
  id_huesped:          inputData.id_huesped    ?? '',
  fecha_in:            inputData.fecha_in,
  fecha_out:           inputData.fecha_out,
  hora_checkin:        ctx.hora_checkin_base,
  hora_checkout:       ctx.hora_checkout_base,
  personas:            inputData.personas,
  monto_total:         inputData.monto_total   ?? '',
  monto_sena:          inputData.monto_sena    ?? '',
  estado:              'pendiente_pago',
  expira_en,
  canal_pago_esperado: inputData.canal_pago_esperado,
  canal_origen:        inputData.canal_origen,
  intentos_pago:       0,
  referencia_mp:       '',
  notas:               inputData.notas         ?? '',
  source_event:        inputData.source_event,
  created_at:          ahora.toISOString(),
  updated_at:          ahora.toISOString()
};

return [{ json: {
  fila,
  inputData,
  precio_pendiente:   inputData.precio_pendiente,
  minutos_expiracion: minutos
}}];

// ── Preparar input para db_recalcular_disponibilidad ─────────
// v2: recálculo COMPLETO (sin scope parcial).
// Se envía solo source_event — sin id_cabanas ni fechas.
//
// ¿Por qué recálculo completo?
// db_recalcular_disponibilidad v8 borra DISPONIBILIDAD_CACHE!A2:R
// antes de escribir. Si se le pasan fechas/cabañas parciales,
// el riesgo es que escriba solo esas filas y borre el resto.
// Hasta que exista una versión de recálculo parcial real
// (que NO borre la cache completa antes de escribir),
// se usa recálculo completo para garantizar integridad.
return [{ json: { source_event: 'prereserva_creada' } }];

// ═══════════════════════════════════════════════════════════════
// NODO FINAL — Resumen
// ═══════════════════════════════════════════════════════════════
// Este nodo recibe directamente como input el output del subworkflow
// db_recalcular_disponibilidad.
// No referenciar el nodo Execute Workflow por nombre, porque si se
// reemplaza o renombra, rompe el resumen final.
// ═══════════════════════════════════════════════════════════════

const fila = $('Preparar Fila PRE_RESERVAS').first().json;

// Output directo del nodo anterior: db_recalcular_disponibilidad
const recalculoOutput = $input.first()?.json ?? {};

const recalculo_fallo =
  !!recalculoOutput.error ||
  recalculoOutput.ok === false;

return [{
  json: {
    ok: true,
    id_prereserva: fila.fila.id_prereserva,
    estado: 'pendiente_pago',
    expira_en: fila.fila.expira_en,
    id_consulta: fila.fila.id_consulta,
    id_cabana: fila.fila.id_cabana,
    fecha_in: fila.fila.fecha_in,
    fecha_out: fila.fila.fecha_out,
    personas: fila.fila.personas,
    hora_checkin: fila.fila.hora_checkin,
    hora_checkout: fila.fila.hora_checkout,
    precio_pendiente: fila.precio_pendiente,
    monto_total: fila.fila.monto_total || null,
    monto_sena: fila.fila.monto_sena || null,
    source_event: fila.fila.source_event,

    recalculo_cache: recalculo_fallo ? 'warning' : 'ok',
    recalculo_error: recalculo_fallo
      ? 'db_recalcular_disponibilidad falló después de crear PRE_RESERVA. Cache puede estar desactualizada. Ejecutar recálculo manual.'
      : null,

    recalculo_resultado: recalculoOutput
  }
}];
